function calculate({ projectArea, initialCostPerSqM, estimatedLifespan, annualEnergySavingsPerSqM, averageElectricityCost, populationBenefited, monetaryValueHealthBenefitPerCapita, annualMaintenanceCostPerSqM, discountRate }) {

    // Input validation and default values
    projectArea = Math.max(0, projectArea || 0);
    initialCostPerSqM = Math.max(0, initialCostPerSqM || 0);
    estimatedLifespan = Math.max(1, estimatedLifespan || 1); // Lifespan must be at least 1 year
    annualEnergySavingsPerSqM = Math.max(0, annualEnergySavingsPerSqM || 0);
    averageElectricityCost = Math.max(0, averageElectricityCost || 0);
    populationBenefited = Math.max(0, populationBenefited || 0);
    monetaryValueHealthBenefitPerCapita = Math.max(0, monetaryValueHealthBenefitPerCapita || 0);
    annualMaintenanceCostPerSqM = Math.max(0, annualMaintenanceCostPerSqM || 0);
    discountRate = Math.max(0, Math.min(0.99, discountRate || 0)); // Cap discount rate below 100% to avoid division by zero/negative results for NPV denominator

    const totalInitialInvestment = projectArea * initialCostPerSqM;

    let totalEnergySavingsValueUndiscounted = 0;
    let totalHealthBenefitsValueUndiscounted = 0;
    let cumulativeDiscountedNetBenefit = 0;
    let cumulativeUndiscountedNetBenefit = 0;
    let paybackPeriod = Infinity;
    let currentCumulativeBenefitForPayback = 0;

    // Handle zero investment case
    if (totalInitialInvestment === 0) {
        return {
            netPresentValue: 0,
            returnOnInvestment: Infinity,
            paybackPeriod: 0,
            totalEnergySavingsValue: 0,
            totalHealthBenefitsValue: 0,
            totalInitialInvestment: 0
        };
    }

    // Calculate annual benefits and costs
    const annualEnergySavingsValue = annualEnergySavingsPerSqM * projectArea * averageElectricityCost;
    const annualHealthBenefitsValue = populationBenefited * monetaryValueHealthBenefitPerCapita;
    const annualMaintenanceCost = annualMaintenanceCostPerSqM * projectArea;

    // Calculate Net Present Value and cumulative benefits over lifespan
    for (let year = 1; year <= estimatedLifespan; year++) {
        const annualNetBenefit = annualEnergySavingsValue + annualHealthBenefitsValue - annualMaintenanceCost;

        // Sum undiscounted totals
        totalEnergySavingsValueUndiscounted += annualEnergySavingsValue;
        totalHealthBenefitsValueUndiscounted += annualHealthBenefitsValue;
        cumulativeUndiscountedNetBenefit += annualNetBenefit;

        // Discount factor
        const discountFactor = (1 + discountRate) ** year;

        // Accumulate discounted net benefits for NPV
        cumulativeDiscountedNetBenefit += annualNetBenefit / discountFactor;

        // Calculate payback period (using undiscounted cash flows for simplicity and common practice)
        if (paybackPeriod === Infinity) {
            currentCumulativeBenefitForPayback += annualNetBenefit;
            if (currentCumulativeBenefitForPayback >= totalInitialInvestment) {
                // Linear interpolation for more precise payback period
                paybackPeriod = year - 1 + (totalInitialInvestment - (currentCumulativeBenefitForPayback - annualNetBenefit)) / annualNetBenefit;
                if (annualNetBenefit <= 0) paybackPeriod = Infinity; // If no positive cash flow, payback is infinite
            }
        }
    }

    const netPresentValue = cumulativeDiscountedNetBenefit - totalInitialInvestment;

    let returnOnInvestment = 0;
    if (totalInitialInvestment > 0) {
        returnOnInvestment = (cumulativeUndiscountedNetBenefit - totalInitialInvestment) / totalInitialInvestment * 100;
    } else if (cumulativeUndiscountedNetBenefit > 0) {
        returnOnInvestment = Infinity; // Infinite ROI if cost is 0 and benefit is positive
    } else {
        returnOnInvestment = 0; // No ROI if no cost and no benefit
    }

    // If net annual benefit is always negative, payback period is infinite.
    if (annualEnergySavingsValue + annualHealthBenefitsValue - annualMaintenanceCost <= 0 && totalInitialInvestment > 0) {
        paybackPeriod = Infinity;
    } else if (totalInitialInvestment < 0) {
        paybackPeriod = 0; // If initial investment is a gain, payback is immediate
    } else if (totalInitialInvestment === 0) {
        paybackPeriod = 0;
    }

    return {
        netPresentValue: netPresentValue,
        returnOnInvestment: returnOnInvestment,
        paybackPeriod: isFinite(paybackPeriod) ? paybackPeriod : 'N/A',
        totalEnergySavingsValue: totalEnergySavingsValueUndiscounted,
        totalHealthBenefitsValue: totalHealthBenefitsValueUndiscounted,
        totalInitialInvestment: totalInitialInvestment
    };
}
